import { useEffect, useState } from "react"
import { io } from "socket.io-client"
import axios from "axios"

const socket = io("http://localhost:5001")

export default function ChatPage({ user }) {
  const [arr, setArr] = useState([])
  const [sel, setSel] = useState(null)
  const [msg, setMsg] = useState("")
  const [list, setList] = useState([])
  const [online, setOnline] = useState([])
  const [typingUser, setTypingUser] = useState("")
  const [search, setSearch] = useState("")
  const [resu, setResu] = useState(null)
  useEffect(() => {
    const f = async () => {
      const res = await axios.get("http://localhost:5001/chat/getChats", {
  headers: {
    Authorization: localStorage.getItem("token")
  }
})
      setArr(res.data)
      
    }
    if (user) f()
  }, [user])

  const load = async (u) => {
    setSel(u)
    const r = [user.phone, u.phone].sort().join("_")
    socket.emit("join_room", r)
    const token = localStorage.getItem("token");

    const res = await axios.get(`http://localhost:5001/chat/getMessages/${phone}`, {
  headers: {
    Authorization: `Bearer ${token}` 
  }
})
    setList(res.data)
  }

  useEffect(() => {
    socket.emit("user_online", user.phone)

    socket.on("online_users", setOnline)

    socket.on("receive_message", m => {
      setList(prev => [...prev, m])
    })

    socket.on("message_read", id => {
      setList(prev => prev.map(m => m._id === id ? { ...m, read: true } : m))
    })

    return () => {
      socket.off("online_users")
      socket.off("receive_message")
      socket.off("message_read")
    }
  }, [user.phone])

  useEffect(() => {
    let t
    socket.on("typing", u => {
      setTypingUser(u)
      clearTimeout(t)
      t = setTimeout(() => setTypingUser(""), 2000)
    })
    return () => socket.off("typing")
  }, [])

  const send = () => {
    if (!msg || !sel) return

    const r = [user.phone, sel.phone].sort().join("_")

    const data = {
      sender: user.phone,
      receiver: sel.phone,
      text: msg,
      room: r,
      read: false
    }

    socket.emit("send_message", data)
    setMsg("")
  }

  const handleRead = id => {
    if (!sel) return
    const r = [user.phone, sel.phone].sort().join("_")
    socket.emit("message_read", { room: r, messageId: id, reader: user.phone })
  }
  const find = async () => {
  if (!search) return

  const r = await axios.get(`http://localhost:5001/user/search/${search}`)
  setResu(r.data)
}

  return (
    <div style={{ display: "flex", height: "100vh" }}>

      {/* LEFT → CHAT LIST */}
      <div style={{ width: "30%", borderRight: "1px solid black", padding: 10 }}>
        <h3>Chats</h3>
        <div style={{ marginBottom: 10 }}>
        <input
          placeholder="Search phone"
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
        <button onClick={find}>Search</button>
      </div>
      {resu && (
        <div
          onClick={() => load(resu)}
          style={{ background: "#ddd", padding: 10, cursor: "pointer" }}
        >
          {resu.name} ({resu.phone})
        </div>
      )}
        {arr.map(u => (
          <div
            key={u._id}
            onClick={() => load(u)}
            style={{ cursor: "pointer", padding: 10 }}
          >
            {u.name}
          </div>
        ))}
      </div>

      {/* RIGHT → CHAT */}
      <div style={{ width: "70%", padding: 10 }}>
        {sel ? (
          <>
            <h3>Chat with {sel.name}</h3>
            <div>Online: {online.includes(sel.phone) ? "Yes" : "No"}</div>

            <div style={{ maxHeight: "60vh", overflowY: "auto" }}>
              {list.map((m, i) => (
                <p
                  key={m._id || i}
                  onMouseEnter={() => handleRead(m._id)}
                  style={{
                    background: m.sender === user.phone ? "#cceeff" : "#fff",
                    padding: 5,
                    borderRadius: 5
                  }}
                >
                  <b>{m.sender}</b>: {m.text}

                  {m.sender === user.phone && (
                    m.read ? " ✓✓" :
                    m.delivered ? " ✓" :
                    " ⏳"
                  )}
                </p>
              ))}
            </div>

            {typingUser && <div>{typingUser} typing...</div>}

            <input
              value={msg}
              onChange={e => {
                setMsg(e.target.value)
                socket.emit("typing_start", {
                  room: [user.phone, sel.phone].sort().join("_"),
                  user: user.phone
                })
              }}
            />

            <button onClick={send}>Send</button>
          </>
        ) : (
          <h3>Select a chat</h3>
        )}
      </div>
    </div>
  )
}
